  ('investigation-d4d4f144-moex-00060', 'investigation-d4d4f144', 'investigation-d4d4f144-moex-114-3f63b028', 'sub-investigation-d4d4f144-04', NULL, 'essay', '證券交易法對於上市有價證券之場外交易有禁止之規定，但明定基於法
律規定所生效力不能經由有價證券集中交易市場之買賣而取得或喪失
證券所有權者，為例外之情形；另對於私募之應募人所持有之有價證券
轉讓限制，亦排除基於法律規定所生效力之移轉，其各規定之立法理由
何在？何謂基於法律規定所生效力？在未有法律規定之例外情形而交
易或移轉者，其民事上之法律效果及違反者之刑事法律責任規定如何？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:38+00:00", "source_pdf_sha1": "0c423246100e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "411", "s": "0421", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "證券交易法與商業會計法", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "財經實務組"}'::jsonb, NULL),
